import{_ as t,o,c as l,a2 as r}from"./chunks/framework.Bjylvv1V.js";const g=JSON.parse('{"title":"고지서 출력/전송","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/billing-notice.md","filePath":"guide/scenarios/billing-notice.md","lastUpdated":null}'),e={name:"guide/scenarios/billing-notice.md"};function i(s,a,n,h,d,c){return o(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="고지서-출력-전송" tabindex="-1">고지서 출력/전송 <a class="header-anchor" href="#고지서-출력-전송" aria-label="Permalink to &quot;고지서 출력/전송&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 15분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 매월 (부과마감 후)</p></blockquote><p>부과마감이 완료된 관리비 고지서를 세대별로 인쇄하거나, 전자고지서·카카오톡·SMS로 전송하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 부과마감 확인        (2분)  → 마감 완료 여부 및 전월비교 검증</span></span>
<span class="line"><span>2. 세대공지사항 입력    (3분)  → 고지서에 첨부할 공지 문구 입력 (선택)</span></span>
<span class="line"><span>3. 고지서 인쇄          (5분)  → 종이 고지서 출력의뢰</span></span>
<span class="line"><span>4. 전자고지서 발송      (2분)  → 전자고지 신청 세대에 발송</span></span>
<span class="line"><span>5. 모바일 발송          (2분)  → 카카오톡/SMS 발송</span></span>
<span class="line"><span>6. 발송이력 확인        (1분)  → 발송 결과 확인</span></span></code></pre></div><hr><h2 id="사전-확인" tabindex="-1">사전 확인 <a class="header-anchor" href="#사전-확인" aria-label="Permalink to &quot;사전 확인&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">부과마감 완료 후 진행</p><p>고지서 발송은 <strong>반드시 부과마감(IMPO9010)이 완료된 후에만</strong> 진행하세요. 마감 전 고지서를 발송하면 금액이 변경될 경우 재발송해야 합니다.</p></div><hr><h2 id="_1단계-부과마감-확인-2분" tabindex="-1">1단계: 부과마감 확인 (2분) <a class="header-anchor" href="#_1단계-부과마감-확인-2분" aria-label="Permalink to &quot;1단계: 부과마감 확인 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> (IMPO9010)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>부과마감 화면 진입</li><li>해당 연월의 <strong>마감 상태</strong> 확인 (마감 완료 여부)</li><li><strong>전월비교</strong> 버튼 클릭하여 전월 대비 증감 확인</li></ol><h3 id="전월비교-확인-포인트" tabindex="-1">전월비교 확인 포인트 <a class="header-anchor" href="#전월비교-확인-포인트" aria-label="Permalink to &quot;전월비교 확인 포인트&quot;">​</a></h3><ul><li>[ ] 세대별 총 부과 금액이 전월 대비 합리적인 범위인가?</li><li>[ ] 특정 항목이 급격히 변동하지 않았는가?</li><li>[ ] 이상 세대(금액이 0원이거나 비정상적으로 높은 세대)가 없는가?</li></ul><p>이상이 있으면 <strong>마감 해제 후 부과 수정</strong>을 먼저 진행하세요.</p><hr><h2 id="_2단계-세대공지사항-입력-3분-선택" tabindex="-1">2단계: 세대공지사항 입력 (3분, 선택) <a class="header-anchor" href="#_2단계-세대공지사항-입력-3분-선택" aria-label="Permalink to &quot;2단계: 세대공지사항 입력 (3분, 선택)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a></p></blockquote><p>고지서 하단 또는 여백에 인쇄할 공지 문구를 입력합니다.</p><h3 id="활용-예시" tabindex="-1">활용 예시 <a class="header-anchor" href="#활용-예시" aria-label="Permalink to &quot;활용 예시&quot;">​</a></h3><ul><li>납부 기한 안내</li><li>장기수선충당금 변경 공지</li><li>관리사무소 휴무 안내</li><li>주차 관련 공지</li></ul><div class="tip custom-block"><p class="custom-block-title">고지서 1줄당 최대 50byte</p><p>한글 기준으로 **1줄에 최대 25자(50byte)**까지 입력 가능합니다. 문구가 길면 줄이 잘리므로 간결하게 작성하세요.</p></div><hr><h2 id="_3단계-고지서-인쇄-5분" tabindex="-1">3단계: 고지서 인쇄 (5분) <a class="header-anchor" href="#_3단계-고지서-인쇄-5분" aria-label="Permalink to &quot;3단계: 고지서 인쇄 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> &gt; 출력의뢰(부과마감)</p></blockquote><p>종이 고지서를 인쇄합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>부과마감 화면에서 <strong>출력의뢰</strong> 버튼 클릭</li><li>출력할 <strong>동·호</strong> 범위 입력 (전체 또는 선택)</li><li><strong>고지서 미리보기</strong>로 내용 확인</li></ol><h3 id="미리보기-확인-포인트" tabindex="-1">미리보기 확인 포인트 <a class="header-anchor" href="#미리보기-확인-포인트" aria-label="Permalink to &quot;미리보기 확인 포인트&quot;">​</a></h3><ul><li>[ ] 세대 정보(동·호수, 세대주명)가 올바른가?</li><li>[ ] 항목별 금액이 정확한가?</li><li>[ ] 납부 기한이 맞는가?</li><li>[ ] 계좌번호 또는 가상계좌가 올바른가?</li><li>[ ] 공지사항 문구가 정상 출력되는가?</li></ul><ol start="4"><li>확인 후 <strong>인쇄</strong> 실행</li></ol><div class="warning custom-block"><p class="custom-block-title">미리보기 확인 필수</p><p>발송 전 미리보기로 반드시 확인하세요. 발송 후에는 취소하기 어렵습니다.</p></div><hr><h2 id="_4단계-전자고지서-발송-2분" tabindex="-1">4단계: 전자고지서 발송 (2분) <a class="header-anchor" href="#_4단계-전자고지서-발송-2분" aria-label="Permalink to &quot;4단계: 전자고지서 발송 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> &gt; 전자고지서 (IMPO9011)</p></blockquote><p>전자고지서 서비스를 신청한 세대에 고지서를 전자 발송합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>전자고지서 화면 진입</li><li><strong>부과 연월</strong> 입력 후 <strong>조회</strong></li><li>발송 대상 세대 목록 확인</li><li><strong>발송</strong> 버튼 클릭</li><li>발송 완료 메시지 확인</li></ol><div class="tip custom-block"><p class="custom-block-title">전자고지서 미신청 세대</p><p>전자고지서 발송 대상은 서비스를 신청한 세대만 포함됩니다. 미신청 세대는 종이 고지서(3단계) 또는 모바일 발송(5단계)으로 안내합니다.</p></div><hr><h2 id="_5단계-모바일-발송-2분" tabindex="-1">5단계: 모바일 발송 (2분) <a class="header-anchor" href="#_5단계-모바일-발송-2분" aria-label="Permalink to &quot;5단계: 모바일 발송 (2분)&quot;">​</a></h2><p>카카오톡 또는 SMS 문자로 고지서를 발송합니다.</p><h3 id="카카오톡-발송" tabindex="-1">카카오톡 발송 <a class="header-anchor" href="#카카오톡-발송" aria-label="Permalink to &quot;카카오톡 발송&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> &gt; 전자고지서 &gt; 카카오톡 발송</p></blockquote><table tabindex="0"><thead><tr><th>발송 방식</th><th>설명</th></tr></thead><tbody><tr><td><strong>단건 발송</strong></td><td>특정 세대 1건씩 발송</td></tr><tr><td><strong>대량 발송</strong></td><td>카카오톡 동의 세대 전체 일괄 발송</td></tr></tbody></table><h3 id="sms-문자-발송" tabindex="-1">SMS 문자 발송 <a class="header-anchor" href="#sms-문자-발송" aria-label="Permalink to &quot;SMS 문자 발송&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> &gt; 모바일발송</p></blockquote><p>관리비 납부 안내 문자를 SMS로 발송합니다.</p><ul><li>발송 대상: 휴대폰 번호가 등록된 세대</li><li>발송 내용: 부과 연월, 청구 금액, 납부 기한, 납부 계좌 등</li></ul><div class="tip custom-block"><p class="custom-block-title">카카오톡 우선 발송</p><p>카카오톡 발송이 가능한 세대는 카카오톡으로 먼저 발송하세요. SMS보다 정보를 더 상세히 전달할 수 있고 비용도 절감됩니다. 카카오톡 미동의 세대는 SMS로 대체 발송됩니다.</p></div><hr><h2 id="_6단계-발송이력-확인-1분" tabindex="-1">6단계: 발송이력 확인 (1분) <a class="header-anchor" href="#_6단계-발송이력-확인-1분" aria-label="Permalink to &quot;6단계: 발송이력 확인 (1분)&quot;">​</a></h2><p>발송 완료 후 발송이력을 확인합니다.</p><h3 id="발송이력-확인-항목" tabindex="-1">발송이력 확인 항목 <a class="header-anchor" href="#발송이력-확인-항목" aria-label="Permalink to &quot;발송이력 확인 항목&quot;">​</a></h3><table tabindex="0"><thead><tr><th>확인 항목</th><th>설명</th></tr></thead><tbody><tr><td><strong>발송 건수</strong></td><td>총 발송 세대 수</td></tr><tr><td><strong>성공 건수</strong></td><td>정상 수신 세대 수</td></tr><tr><td><strong>실패 건수</strong></td><td>발송 실패 세대 수 (번호 오류, 수신 거부 등)</td></tr><tr><td><strong>발송 일시</strong></td><td>발송이 완료된 시각</td></tr></tbody></table><p>발송 실패 건은 <strong>번호 재확인 후 재발송</strong>하거나, 종이 고지서를 우편으로 발송하세요.</p><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="특정-세대-고지서-금액이-이상해요" tabindex="-1">특정 세대 고지서 금액이 이상해요 <a class="header-anchor" href="#특정-세대-고지서-금액이-이상해요" aria-label="Permalink to &quot;특정 세대 고지서 금액이 이상해요&quot;">​</a></h3><p><strong>원인</strong>: 부과 계산 오류, 별도금액 잘못 입력, 부과제외 세대 미등록 등입니다. <strong>해결</strong>: 부과마감을 해제하고 <a href="/impo/process.html">부과처리</a>에서 해당 세대 금액을 재확인하세요. 수정 후 다시 마감하고 고지서를 재발송합니다.</p><h3 id="전자고지서-발송-대상-세대가-없어요" tabindex="-1">전자고지서 발송 대상 세대가 없어요 <a class="header-anchor" href="#전자고지서-발송-대상-세대가-없어요" aria-label="Permalink to &quot;전자고지서 발송 대상 세대가 없어요&quot;">​</a></h3><p><strong>원인</strong>: 전자고지서 서비스 신청 세대가 등록되지 않은 상태입니다. <strong>해결</strong>: <a href="/impo/basic.html">기초정보</a>에서 전자고지서 수신 동의 세대가 등록되어 있는지 확인하세요. 미등록이라면 세대 신청 후 등록합니다.</p><h3 id="카카오톡-발송이-실패해요" tabindex="-1">카카오톡 발송이 실패해요 <a class="header-anchor" href="#카카오톡-발송이-실패해요" aria-label="Permalink to &quot;카카오톡 발송이 실패해요&quot;">​</a></h3><p><strong>원인</strong>: 세대의 카카오톡 동의가 없거나 번호가 변경된 경우입니다. <strong>해결</strong>: 카카오톡 미동의 세대는 SMS로 자동 대체 발송되는 경우가 많습니다. 번호 변경이 원인이라면 세대 정보에서 연락처를 갱신하세요.</p><h3 id="고지서-공지사항-문구가-잘려요" tabindex="-1">고지서 공지사항 문구가 잘려요 <a class="header-anchor" href="#고지서-공지사항-문구가-잘려요" aria-label="Permalink to &quot;고지서 공지사항 문구가 잘려요&quot;">​</a></h3><p><strong>원인</strong>: 1줄에 입력 가능한 최대 글자 수(한글 25자/50byte)를 초과했습니다. <strong>해결</strong>: 문구를 줄이거나 두 줄로 나누어 입력하세요. 특수문자나 영문 혼용 시 byte 수가 달라질 수 있으니 미리보기로 반드시 확인하세요.</p><h3 id="이미-발송한-고지서를-취소하고-싶어요" tabindex="-1">이미 발송한 고지서를 취소하고 싶어요 <a class="header-anchor" href="#이미-발송한-고지서를-취소하고-싶어요" aria-label="Permalink to &quot;이미 발송한 고지서를 취소하고 싶어요&quot;">​</a></h3><p><strong>원인</strong>: 금액 오류 또는 공지사항 오입력 후 발송한 경우입니다. <strong>해결</strong>: 전자고지서·모바일 발송은 <strong>취소가 어렵습니다</strong>. 오류가 있다면 수정 내용을 별도 문자로 안내하거나, 수정된 고지서를 재발송하세요. 향후에는 발송 전 <strong>미리보기 확인</strong>을 철저히 하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/impo/closing.html">부과마감</a> - 마감 처리 및 고지서 출력의뢰 (IMPO9010)</li><li><a href="/impo/closing.html">전자고지서</a> - 전자 발송 및 카카오톡·SMS (IMPO9011)</li><li><a href="/dang/dang-info.html">단지정보</a> - 세대공지사항 입력</li><li><a href="/guide/scenarios/billing.html">관리비 부과</a> - 부과마감 이전 부과 처리 전체 흐름</li><li><a href="/impo/inquiry.html">부과조회</a> - 발송 후 세대별 고지 내역 조회</li></ul>`,72)])])}const u=t(e,[["render",i]]);export{g as __pageData,u as default};
